      "title": "Square Root Spiral Construction",
      "unit_name": "Number System",
      "chapter_name": "Number System",
      "details": "Construct the square root spiral. Apply computational thinking to represent rational and irrational numbers through algorithms and visual models."
    },
    {
      "type": "activity",
      "title": "Tower of Hanoi Puzzle",
      "unit_name": "Algebra",
      "chapter_name": "Sequences and Progressions",
      "details": "Solve the Tower of Hanoi puzzle. Use computational thinking to identify patterns, write step-by-step rules."
    },
    {
      "type": "activity",
      "title": "Geometric Models for Identities",
      "unit_name": "Algebra",
      "chapter_name": "Exploring Algebraic Identities",
      "details": "Visualise algebraic identities using geometric models. Visualising factorisation of quadratic expressions through algebra tiles."
    },
    {
      "type": "activity",
      "title": "Floor Plan Representation",
      "unit_name": "Coordinate Geometry",
      "chapter_name": "Coordinate Geometry",
      "details": "Represent a floor plan on a grid using coordinates. Compute the distance between two points."
    },
    {
      "type": "activity",
      "title": "Euclid's Definitions and Constructions",
      "unit_name": "Geometry",
      "chapter_name": "Introduction to Euclid's Geometry",
      "details": "Constructing a square with a given side as described in the Baudhayana's Sulbasutras. Justify simple constructions using axioms."
    },
    {
      "type": "activity",
      "title": "Paper Manipulation Activities",
      "unit_name": "Geometry",
      "chapter_name": "Quadrilaterals",
      "details": "Engage in drawing, measurement and paper manipulation activities to discover geometric patterns involving triangles and 4-gons."
    },
    {
      "type": "activity",
      "title": "Cultural Motifs Analysis",
      "unit_name": "Geometry",
      "chapter_name": "Circles",
      "details": "Identify cultural motifs involving circles, for example, the Dharmachakra, Ashoka Chakra, Sudarshan Chakra."
    },
    {
      "type": "activity",
      "title": "Squaring a Rectangle Proof",
      "unit_name": "Mensuration",
      "chapter_name": "Area and Perimeter",
      "details": "Explain the classical problem of 'squaring' a given shape. Explain how ancient civilisations approximated the area of a circle."
    },
    {
      "type": "activity",
      "title": "Data Analysis Projects",
      "unit_name": "Statistics and Probability",
      "chapter_name": "Statistics",
      "details": "Collect, organise, visualise and interpret data to answer a statistical investigative question. Apply computational thinking strategies to analyse real-life data."
    },
    {
      "type": "activity",
      "title": "Random Experiment Simulation",
      "unit_name": "Statistics and Probability",
      "chapter_name": "Introduction to Probability",
      "details": "Use computational thinking strategies, such as pattern recognition and simulation, to model random experiments and estimate probabilities."
    }
